import{_ as a,o as n,c as r,S as i}from"./chunks/framework.C6RQlTYc.js";const c=JSON.parse('{"title":"机器学习","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_2-machine_learning.md","filePath":"直击概念/17ai/s_ai_2-machine_learning.md","lastUpdated":1778207238000}'),t={name:"直击概念/17ai/s_ai_2-machine_learning.md"};function l(o,e,s,g,h,u){return n(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="机器学习" tabindex="-1">机器学习 <a class="header-anchor" href="#机器学习" aria-label="Permalink to &quot;机器学习&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>机器学习（Machine Learning，ML）是 AI 的核心子领域，核心思想是<strong>让计算机从数据中自动学习规律和模式，而不需要显式编程</strong>。传统程序是&quot;给定规则+数据 → 输出结果&quot;，而机器学习是&quot;给定数据+结果 → 学习出规则&quot;。</p><p>机器学习本质上是<strong>寻找一个函数 f(x)，使得给定输入 x 后，输出 ŷ 尽可能接近真实值 y</strong>。这个寻找过程称为&quot;训练&quot;。</p><h2 id="三大学习范式" tabindex="-1">三大学习范式 <a class="header-anchor" href="#三大学习范式" aria-label="Permalink to &quot;三大学习范式&quot;">​</a></h2><h3 id="监督学习-supervised-learning" tabindex="-1">监督学习（Supervised Learning） <a class="header-anchor" href="#监督学习-supervised-learning" aria-label="Permalink to &quot;监督学习（Supervised Learning）&quot;">​</a></h3><p>训练数据包含<strong>输入和对应的标签</strong>，目标是学习从输入到标签的映射关系。</p><ul><li><strong>分类（Classification）</strong>：预测离散标签，如垃圾邮件检测、图像识别</li><li><strong>回归（Regression）</strong>：预测连续数值，如房价预测、温度预测</li><li>常见算法：线性回归、决策树、SVM、神经网络</li></ul><h3 id="无监督学习-unsupervised-learning" tabindex="-1">无监督学习（Unsupervised Learning） <a class="header-anchor" href="#无监督学习-unsupervised-learning" aria-label="Permalink to &quot;无监督学习（Unsupervised Learning）&quot;">​</a></h3><p>训练数据<strong>只有输入没有标签</strong>，目标是发现数据的内在结构。</p><ul><li><strong>聚类（Clustering）</strong>：将相似数据分组，如用户分群、文档归类</li><li><strong>降维（Dimensionality Reduction）</strong>：压缩数据维度并保留关键信息，如 PCA</li><li><strong>关联规则</strong>：发现数据中的关联关系，如购物篮分析</li></ul><h3 id="强化学习-reinforcement-learning" tabindex="-1">强化学习（Reinforcement Learning） <a class="header-anchor" href="#强化学习-reinforcement-learning" aria-label="Permalink to &quot;强化学习（Reinforcement Learning）&quot;">​</a></h3><p>智能体通过与<strong>环境交互</strong>，根据奖励信号学习最优策略。</p><ul><li><strong>核心要素</strong>：Agent、Environment、State、Action、Reward</li><li><strong>典型算法</strong>：Q-Learning、Policy Gradient、PPO</li><li><strong>代表性应用</strong>：AlphaGo、自动驾驶、游戏 AI</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>监督学习和无监督学习的区别？各举一个前端场景。</li><li>什么是过拟合？如何判断和防止？</li><li>机器学习模型部署到前端的几种方式（如 TensorFlow.js）</li></ul><h2 id="训练与推理" tabindex="-1">训练与推理 <a class="header-anchor" href="#训练与推理" aria-label="Permalink to &quot;训练与推理&quot;">​</a></h2><ul><li><strong>训练（Training）</strong>：用大量数据和算力学习模型参数的过程，在服务器端进行。</li><li><strong>推理（Inference）</strong>：用训练好的模型对新数据进行预测，可以在客户端（如浏览器中通过 WebGPU）进行。</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://en.wikipedia.org/wiki/Machine_learning" target="_blank" rel="noreferrer">Machine Learning - Wikipedia</a></li><li><a href="https://developers.google.com/machine-learning/crash-course" target="_blank" rel="noreferrer">Google Machine Learning Crash Course</a></li></ul>',20)])])}const p=a(t,[["render",l]]);export{c as __pageData,p as default};
